import React, { useState } from "react";
import Dice from "react-dice-roll";
import RescueModal from "./RescueModal";

const BOARD_SIZE = 40;
const MANNA_INDEX = 25;

function App() {
  const [players, setPlayers] = useState([
    { id: 1, name: "Player 1", position: 0, money: 1500 },
    { id: 2, name: "Player 2", position: 0, money: 1500 },
  ]);

  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [showRescueModal, setShowRescueModal] = useState(false);
  const [rescueInfo, setRescueInfo] = useState({});

  const [mannaSponsor, setMannaSponsor] = useState(null);
  const [mannaAmount, setMannaAmount] = useState(null);

  const currentPlayer = players[currentPlayerIndex];

  const movePlayer = (roll) => {
    const updatedPlayers = [...players];
    let player = { ...updatedPlayers[currentPlayerIndex] };

    player.position = (player.position + roll) % BOARD_SIZE;

    // MANNA FOODS LOGIC
    if (player.position === MANNA_INDEX) {
      if (!mannaSponsor) {
        const amount = prompt(
          "Manna Foods\n\nCover the cost of a Manna Foods Banquet\n\nPay whatever price you like"
        );

        const numAmount = Number(amount);

        if (!numAmount || player.money < numAmount) {
          setRescueInfo({ player, rent: numAmount || 0 });
          setShowRescueModal(true);
          return;
        }

        player.money -= numAmount;
        setMannaSponsor(player.id);
        setMannaAmount(numAmount);
      } else {
        if (player.money < mannaAmount) {
          setRescueInfo({ player, rent: mannaAmount });
          setShowRescueModal(true);
          return;
        }

        player.money -= mannaAmount;

        const sponsorIndex = players.findIndex(
          (p) => p.id === mannaSponsor
        );
        updatedPlayers[sponsorIndex].money += mannaAmount;
      }
    }

    updatedPlayers[currentPlayerIndex] = player;
    setPlayers(updatedPlayers);

    setCurrentPlayerIndex(
      (currentPlayerIndex + 1) % players.length
    );
  };


  return (
    <div style={{ padding: 20 }}>
      <h1>TorahPoly</h1>

      <h2>Current Turn: {currentPlayer.name}</h2>

      <Dice onRoll={(roll) => movePlayer(roll)} />

      <h3>Players</h3>
      {players.map((p) => (
        <div key={p.id}>
          {p.name} — Position: {p.position} — Money: ${p.money}
        </div>
      ))}

      {mannaSponsor && (
        <p>
          Manna Foods sponsored for ${mannaAmount}
        </p>
      )}


      <RescueModal
        open={showRescueModal}
        onClose={() => setShowRescueModal(false)}
        currentPlayer={rescueInfo.player || {}}
        rentAmount={rescueInfo.rent}
        players={players}
        setPlayers={setPlayers}
      />
    </div>
  );
};

export default App;
